   class Game:
       def __init__(self):
           self.board = Board()
           self.current_player = 'black'
           self.game_over = False

       def setup_board(self):
           self.board.setup_initial_configuration()

       def switch_player(self):
           self.current_player = 'white' if self.current_player == 'black' else 'black'

       def make_move(self, move):
           if self.board.is_valid_move(move, self.current_player):
               self.board.move_piece(move)
               self.switch_player()
           else:
               print("Invalid move. Please try again.")

       def is_game_over(self):
           # Check win/draw conditions
           return False

       def display_board(self):
           self.board.print_board()

   class Player:
       def make_turn(self, game):
           while True:
               move_input = input(f"{game.current_player}'s turn. Enter your move (e.g., a1-b2): ")
               if game.board.is_valid_move(move_input, game.current_player):
                   break
               else:
                   print("Invalid move. Please try again.")
           return move_input

   class Board:
       def __init__(self):
           self.state = [[None for _ in range(8)] for _ in range(8)]

       def setup_initial_configuration(self):
           for row in range(3):
               for col in range(0, 8, 2):
                   self.state[row][col] = Piece('black')
           for row in range(5, 8):
               for col in range(1, 9, 2):
                   self.state[row][col] = Piece('white')

       def print_board(self):
           from termcolor import colored
           header = "   A B C D E F G H"
           print(header)
           for row in range(8):
               line = f"{row+1} | "
               for col in range(8):
                   if self.state[row][col]:
                       piece_color = 'red' if self.state[row][col].color == 'black' else 'blue'
                       piece_char = 'B' if self.state[row][col].is_kinged else 'b'  # B for black, b for white
                       line += colored(piece_char, piece_color) + " | "
                   else:
                       line += "   | "
               print(line)
           print(header)

       def move_piece(self, move):
           start_col = ord(move[0]) - ord('A')
           start_row = int(move[1]) - 1
           end_col = ord(move[3]) - ord('A')
           end_row = int(move[4]) - 1

           if self.state[start_row][start_col]:
               self.state[end_row][end_col] = self.state[start_row][start_col]
               self.state[start_row][start_col] = None
               if abs(start_row - end_row) == 2:
                   # Handle capture
                   captured_row = (start_row + end_row) // 2
                   captured_col = (start_col + end_col) // 2
                   self.state[captured_row][captured_col] = None

       def is_valid_move(self, move, player):
           if len(move) != 4:
               return False
           start_col = ord(move[0]) - ord('A')
           start_row = int(move[1]) - 1
           end_col = ord(move[2]) - ord('A')
           end_row = int(move[3]) - 1

           if not (0 <= start_row < 8 and 0 <= end_row < 8 and 0 <= start_col < 8 and 0 <= end_col < 8):
               return False

           piece = self.state[start_row][start_col]
           if piece is None or piece.color != player:
               return False

           if abs(start_row - end_row) not in [1, 2]:
               return False
           if abs(start_col - end_col) not in [1, 0]:
               return False

           # Check for capture rules

           return True

   class Piece:
       def __init__(self, color):
           self.color = color
           self.is_kinged = False

       def king_me(self):
           self.is_kinged = True
